func (q *Queries) PruneSpans(ctx context.Context, arg PruneSpansParams) (int64, error) {
	result, err := q.db.Exec(ctx, pruneSpans,
		arg.OrgID,
		arg.SessionIds,
		arg.KeepTraceIds,
		arg.KeepSpanIds,
	)
	if err != nil {
		return 0, err
	}
	return result.RowsAffected(), nil
}

